import 'login_model.dart';class UserModel {  bool? success;  String? token;  UserData? data;  UserModel({this.success, this.token, this.data});  UserModel.fromJson(Map<String, dynamic> json) {    success = json['success'];    token = json['token'];    data = json['data'] != null ? new UserData.fromJson(json['data']) : null;  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['success'] = this.success;    data['token'] = this.token;    if (this.data != null) {      data['data'] = this.data!.toJson();    }    return data;  }}